"""
Bybit API Integration for Scalping Bot
Handles all API interactions including orders, positions, and market data
"""

import hmac
import hashlib
import time
import json
import urllib.request
from typing import Dict, List, Optional, Tuple
from dataclasses import dataclass
from datetime import datetime

@dataclass
class TradeConfig:
    API_KEY = "MGvC4I8CqCHisK2txU"
    API_SECRET = "a8ETBxiRAXN8emdCKbAxBKf47qwSrbiehy4R"
    BASE_URL = "https://api-demo.bybit.com"
    MIN_USDT_VALUE = 5  # Minimum USDT per trade
    DEFAULT_LEVERAGE = 50
    EXCLUDED_PAIRS = ['BTCUSDT', 'ETHUSDT', 'BTCUSD', 'ETHUSD']

class BybitAPI:
    def __init__(self):
        self.api_key = TradeConfig.API_KEY
        self.api_secret = TradeConfig.API_SECRET
        self.base_url = TradeConfig.BASE_URL
        self.recv_window = "5000"

    def _generate_signature(self, timestamp: str, params: Dict) -> str:
        """Generate HMAC-SHA256 signature"""
        if params:
            param_str = "&".join([f"{k}={v}" for k, v in sorted(params.items())])
        else:
            param_str = ""

        sign_str = f"{timestamp}{self.api_key}{self.recv_window}{param_str}"
        signature = hmac.new(
            self.api_secret.encode(),
            sign_str.encode(),
            hashlib.sha256
        ).hexdigest()
        return signature, param_str

    def _make_request(self, endpoint: str, params: Dict = None, method: str = "GET") -> Dict:
        """Make authenticated API request"""
        timestamp = str(int(time.time() * 1000))
        signature, param_str = self._generate_signature(timestamp, params or {})

        headers = {
            "X-BAPI-API-KEY": self.api_key,
            "X-BAPI-TIMESTAMP": timestamp,
            "X-BAPI-RECV-WINDOW": self.recv_window,
            "X-BAPI-SIGN": signature,
            "Content-Type": "application/json"
        }

        if method == "GET":
            url = f"{self.base_url}{endpoint}"
            if param_str:
                url += f"?{param_str}"
            req = urllib.request.Request(url, headers=headers, method=method)
        else:
            url = f"{self.base_url}{endpoint}"
            req = urllib.request.Request(
                url,
                data=json.dumps(params).encode(),
                headers=headers,
                method=method
            )

        try:
            with urllib.request.urlopen(req, timeout=10) as response:
                return json.loads(response.read().decode())
        except Exception as e:
            return {"retCode": -1, "retMsg": str(e)}

    def get_wallet_balance(self) -> Dict:
        """Get USDT wallet balance"""
        result = self._make_request("/v5/account/wallet-balance", {"accountType": "UNIFIED"})
        if result.get("retCode") == 0:
            for item in result["result"]["list"]:
                for coin in item.get("coin", []):
                    if coin["coin"] == "USDT":
                        return {
                            "available": float(coin.get("availableToWithdraw", 0)),
                            "wallet": float(coin.get("walletBalance", 0)),
                            "equity": float(coin.get("equity", 0))
                        }
        return {"available": 0, "wallet": 0, "equity": 0}

    def get_available_balance(self) -> float:
        """Get available USDT balance for trading"""
        balance = self.get_wallet_balance()
        return balance.get("available", 0)

    def get_all_symbols(self) -> List[Dict]:
        """Get all perpetual futures symbols"""
        result = self._make_request("/v5/market/instruments-info", {
            "category": "linear",
            "status": "Trading"
        })

        symbols = []
        if result.get("retCode") == 0:
            for item in result["result"]["list"]:
                symbol = item["symbol"]
                # Exclude BTC and ETH pairs
                if any(excluded in symbol for excluded in TradeConfig.EXCLUDED_PAIRS):
                    continue
                # Only USDT perpetuals
                if symbol.endswith("USDT"):
                    symbols.append({
                        "symbol": symbol,
                        "baseCoin": item["baseCoin"],
                        "quoteCoin": item["quoteCoin"],
                        "leverageFilter": item.get("leverageFilter", {}),
                        "lotSizeFilter": item.get("lotSizeFilter", {}),
                        "priceFilter": item.get("priceFilter", {})
                    })
        return symbols

    def get_max_leverage(self, symbol: str) -> int:
        """Get maximum leverage for a symbol"""
        result = self._make_request("/v5/market/instruments-info", {
            "category": "linear",
            "symbol": symbol
        })

        if result.get("retCode") == 0:
            item = result["result"]["list"][0]
            leverage = item.get("leverageFilter", {})
            max_lev = int(float(leverage.get("maxLeverage", 50)))
            return min(max_lev, TradeConfig.DEFAULT_LEVERAGE)
        return TradeConfig.DEFAULT_LEVERAGE

    def set_leverage(self, symbol: str, leverage: int) -> bool:
        """Set leverage for a symbol"""
        params = {
            "category": "linear",
            "symbol": symbol,
            "buyLeverage": str(leverage),
            "sellLeverage": str(leverage)
        }
        result = self._make_request("/v5/position/set-leverage", params, "POST")
        return result.get("retCode") == 0

    def get_klines(self, symbol: str, interval: str = "1", limit: int = 100) -> List[Dict]:
        """Get candlestick data"""
        result = self._make_request("/v5/market/kline", {
            "category": "linear",
            "symbol": symbol,
            "interval": interval,
            "limit": limit
        })

        if result.get("retCode") == 0:
            candles = []
            for item in result["result"]["list"]:
                candles.append({
                    "timestamp": int(item[0]),
                    "open": float(item[1]),
                    "high": float(item[2]),
                    "low": float(item[3]),
                    "close": float(item[4]),
                    "volume": float(item[5])
                })
            return candles
        return []

    def get_orderbook(self, symbol: str, limit: int = 50) -> Dict:
        """Get order book data"""
        result = self._make_request("/v5/market/orderbook", {
            "category": "linear",
            "symbol": symbol,
            "limit": limit
        })

        if result.get("retCode") == 0:
            data = result["result"]
            return {
                "bids": [[float(x[0]), float(x[1])] for x in data.get("b", [])],
                "asks": [[float(x[0]), float(x[1])] for x in data.get("a", [])],
                "timestamp": data.get("ts", 0)
            }
        return {"bids": [], "asks": [], "timestamp": 0}

    def get_recent_trades(self, symbol: str, limit: int = 100) -> List[Dict]:
        """Get recent trades"""
        result = self._make_request("/v5/market/recent-trade", {
            "category": "linear",
            "symbol": symbol,
            "limit": limit
        })

        if result.get("retCode") == 0:
            return [{
                "price": float(x["price"]),
                "size": float(x["size"]),
                "side": x["side"],
                "time": x["time"]
            } for x in result["result"]["list"]]
        return []

    def get_positions(self, symbol: str = None) -> List[Dict]:
        """Get open positions"""
        params = {"category": "linear", "settleCoin": "USDT"}
        if symbol:
            params["symbol"] = symbol

        result = self._make_request("/v5/position/list", params)

        positions = []
        if result.get("retCode") == 0:
            for item in result["result"]["list"]:
                size = float(item.get("size", 0))
                if size > 0:
                    positions.append({
                        "symbol": item["symbol"],
                        "side": item["side"],
                        "size": size,
                        "entryPrice": float(item.get("avgPrice", 0)),
                        "leverage": int(float(item.get("leverage", 1))),
                        "unrealisedPnl": float(item.get("unrealisedPnl", 0)),
                        "markPrice": float(item.get("markPrice", 0)),
                        "liqPrice": float(item.get("liqPrice", 0)) if item.get("liqPrice") else 0,
                        "stopLoss": float(item.get("stopLoss", 0)) if item.get("stopLoss") else 0,
                        "takeProfit": float(item.get("takeProfit", 0)) if item.get("takeProfit") else 0
                    })
        return positions

    def get_open_orders(self, symbol: str = None) -> List[Dict]:
        """Get open orders"""
        params = {"category": "linear", "settleCoin": "USDT"}
        if symbol:
            params["symbol"] = symbol

        result = self._make_request("/v5/order/realtime", params)

        orders = []
        if result.get("retCode") == 0:
            for item in result["result"]["list"]:
                orders.append({
                    "orderId": item["orderId"],
                    "symbol": item["symbol"],
                    "side": item["side"],
                    "orderType": item["orderType"],
                    "qty": float(item["qty"]),
                    "price": float(item["price"]),
                    "stopLoss": float(item["stopLoss"]) if item.get("stopLoss") else 0,
                    "takeProfit": float(item["takeProfit"]) if item.get("takeProfit") else 0
                })
        return orders

    def place_order(self, symbol: str, side: str, qty: float, 
                    stop_loss: float = 0, take_profit: float = 0) -> Dict:
        """Place market order with SL/TP"""
        params = {
            "category": "linear",
            "symbol": symbol,
            "side": side,
            "orderType": "Market",
            "qty": str(qty),
            "timeInForce": "GTC",
            "positionIdx": 0
        }

        if stop_loss > 0:
            params["stopLoss"] = str(stop_loss)
        if take_profit > 0:
            params["takeProfit"] = str(take_profit)

        result = self._make_request("/v5/order/create", params, "POST")
        return result

    def close_position(self, symbol: str) -> Dict:
        """Close position for symbol"""
        params = {
            "category": "linear",
            "symbol": symbol,
            "orderType": "Market",
            "timeInForce": "IOC",
            "closeOnTrigger": True
        }

        result = self._make_request("/v5/order/create", params, "POST")
        return result

    def set_trading_stop(self, symbol: str, side: str, 
                         stop_loss: float = 0, take_profit: float = 0) -> Dict:
        """Set SL/TP for existing position"""
        params = {
            "category": "linear",
            "symbol": symbol,
            "positionIdx": 0
        }

        if stop_loss > 0:
            params["stopLoss"] = str(stop_loss)
        if take_profit > 0:
            params["takeProfit"] = str(take_profit)

        result = self._make_request("/v5/position/trading-stop", params, "POST")
        return result

    def get_tickers(self, symbol: str = None) -> List[Dict]:
        """Get 24h ticker data"""
        params = {"category": "linear"}
        if symbol:
            params["symbol"] = symbol

        result = self._make_request("/v5/market/tickers", params)

        tickers = []
