            for item in result["result"]["list"]:
                if symbol and item["symbol"] != symbol:
                    continue
                tickers.append({
                    "symbol": item["symbol"],
                    "lastPrice": float(item["lastPrice"]),
                    "indexPrice": float(item["indexPrice"]),
